<?php $events=isset($data['events'])&&is_array($data['events'])?$data['events']:[]; ?>
<div class="admin-heading"><div><p class="eyebrow">Append-only review</p><h1 class="heading-admin">Audit log</h1><p class="muted">Administrative changes include actor, action, target, before and after values, timestamp, request ID, minimized network identifier, and reason when required.</p></div><a class="button button-ghost" href="<?= $url('admin.audit.export', [], '/admin/audit/export') ?>">Export authorized view</a></div><section class="card card-pad"><form class="form-grid" method="get"><label class="field"><span>Administrator or action</span><input name="q" value="<?= $esc((string)($data['query']??'')) ?>"></label><label class="field"><span>Severity</span><select name="severity"><option>All</option><option>Security</option><option>Payment</option><option>Content</option></select></label><button class="button button-ghost">Filter log</button></form></section><section class="card u-overflow-hidden"><div class="data-table-wrap u-borderless"><table class="data-table"><thead><tr><th>Time</th><th>Administrator</th><th>Action</th><th>Target</th><th>Request</th><th>Review</th></tr></thead><tbody><?php foreach($events as $event): ?><tr><td><?= $esc($event['time']) ?></td><td><?= $esc($event['actor']) ?></td><td><?= $esc($event['action']) ?></td><td><?= $esc($event['target']) ?></td><td><code><?= $esc($event['request_id']) ?></code></td><td><a href="<?= $esc($event['url']) ?>">Details</a></td></tr><?php endforeach; ?><?php if(!$events): ?><tr><td colspan="6">No events match the current filter.</td></tr><?php endif; ?></tbody></table></div></section>
